import { NestFactory } from '@nestjs/core';
import { AppModule } from './app.module';
import { ConfigService } from '@nestjs/config';
import { ValidationPipe } from '@nestjs/common';

async function bootstrap() {
  const app = await NestFactory.create(AppModule);
  const configService = app.get(ConfigService);

  app.setGlobalPrefix('api');
  app.useGlobalPipes(new ValidationPipe({ whitelist: true, transform: true }));

  const port = configService.get<number>('PORT') || 3005;
  await app.listen(port);
  console.log(`Backend is running on: http://localhost:${port}/api`);
}
bootstrap();

import {
  Controller,
  Post,
  Body,
  Get,
  Param,
  UseGuards,
  Request,
} from '@nestjs/common';
import { AIService } from './ai.service';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { PatientsService } from '../patients/patients.service';

@Controller('ai')
@UseGuards(JwtAuthGuard)
export class AiController {
  constructor(
    private aiService: AIService,
    private patientsService: PatientsService,
  ) {}

  @Post('query')
  async query(@Body('prompt') prompt: string) {
    return this.aiService.chat([{ role: 'user', content: prompt }]);
  }

  @Get('summarize/:patientId')
  async summarizePatient(
    @Param('patientId') patientId: string,
    @Request() req: any,
  ) {
    const patient = await this.patientsService.findOne(
      patientId,
      req.user.orgId,
    );
    return this.aiService.generateClinicalSummary(patient);
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import axios from 'axios';

@Injectable()
export class AIService {
  private readonly logger = new Logger(AIService.name);
  private readonly endpoint: string;
  private readonly model: string;

  constructor(private configService: ConfigService) {
    this.endpoint =
      this.configService.get<string>('LLM_ENDPOINT') ||
      'http://localhost:1234/v1';
    this.model = this.configService.get<string>('LLM_MODEL') || 'local-model';
  }

  async chat(messages: { role: string; content: string }[]) {
    try {
      this.logger.log(`Sending request to LLM: ${this.endpoint}`);
      const response = await axios.post(`${this.endpoint}/chat/completions`, {
        model: this.model,
        messages,
        temperature: 0.7,
      });

      return response.data.choices[0].message;
    } catch (error) {
      this.logger.error(`LLM Request failed: ${error.message}`);
      throw new Error(`AI Service Unavailable: ${error.message}`);
    }
  }

  async generateClinicalSummary(patientData: any) {
    const prompt = `You are a clinical assistant. Summarize the following patient record in plain terms for a family member: ${JSON.stringify(patientData)}`;
    return this.chat([{ role: 'user', content: prompt }]);
  }
}

