import { Injectable } from '@nestjs/common';
import { PassportStrategy } from '@nestjs/passport';
import { ExtractJwt, Strategy } from 'passport-jwt';
import { ConfigService } from '@nestjs/config';

@Injectable()
export class JwtStrategy extends PassportStrategy(Strategy) {
  constructor(private configService: ConfigService) {
    super({
      jwtFromRequest: ExtractJwt.fromAuthHeaderAsBearerToken(),
      ignoreExpiration: false,
      secretOrKey:
        configService.get<string>('JWT_SECRET') || 'default-secret-change-me',
    });
  }

  async validate(payload: any) {
    return {
      userId: payload.sub,
      email: payload.email,
      role: payload.role,
      orgId: payload.orgId,
    };
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { PrismaService } from '../database/prisma.service';
import { AIService } from '../ai/ai.service';
import * as fs from 'fs';
// @ts-ignore
import pdf from 'pdf-parse';

@Injectable()
export class DocumentsService {
  private readonly logger = new Logger(DocumentsService.name);

  constructor(
    private prisma: PrismaService,
    private aiService: AIService,
  ) {}

  async create(patientId: string, file: Express.Multer.File) {
    const document = await this.prisma.document.create({
      data: {
        patientId,
        fileName: file.originalname,
        fileType: file.mimetype,
        filePath: file.path,
        status: 'PROCESSING',
      },
    });

    // Fire and forget processing to keep API responsive
    this.processDocument(document.id).catch((err) => {
      this.logger.error(
        `Error processing document ${document.id}: ${err.message}`,
      );
    });

    return document;
  }

  async processDocument(documentId: string) {
    const doc = await this.prisma.document.findUnique({
      where: { id: documentId },
    });
    if (!doc) return;

    try {
      let extractedText = '';

      if (doc.fileType === 'application/pdf') {
        const dataBuffer: Buffer = fs.readFileSync(doc.filePath);
        const data: any = await pdf(dataBuffer);
        extractedText = data.text;
      } else {
        // Fallback for text files or simple extraction
        extractedText = fs.readFileSync(doc.filePath, 'utf8');
      }

      // Use AI to summarize and classify the clinical data
      const aiResponse: any = await this.aiService.chat([
        {
          role: 'system',
          content:
            'You are a clinical document parser. Extract the diagnosis, medications, and clinical summary from the following text into a structured JSON format.',
        },
        { role: 'user', content: extractedText },
      ]);

      await this.prisma.document.update({
        where: { id: documentId },
        data: {
          metadata: aiResponse.content,
          status: 'COMPLETED',
        },
      });

      this.logger.log(`Document ${documentId} processed successfully.`);
    } catch (error) {
      await this.prisma.document.update({
        where: { id: documentId },
        data: { status: 'FAILED' },
      });
      throw error;
    }
  }

  async findAllByPatient(patientId: string) {
    return this.prisma.document.findMany({
      where: { patientId },
      orderBy: { createdAt: 'desc' },
    });
  }
}

import {
  Controller,
  Get,
  Post,
  Body,
  Param,
  UseGuards,
  Request,
  Patch,
} from '@nestjs/common';
import { PatientsService } from './patients.service';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';

@Controller('patients')
@UseGuards(JwtAuthGuard)
export class PatientsController {
  constructor(private patientsService: PatientsService) {}

  @Get()
  async findAll(@Request() req: any) {
    return this.patientsService.findAll(req.user.orgId);
  }

  @Get(':id')
  async findOne(@Param('id') id: string, @Request() req: any) {
    return this.patientsService.findOne(id, req.user.orgId);
  }

  @Post()
  async create(@Body() fhirResource: any, @Request() req: any) {
    return this.patientsService.create(req.user.orgId, fhirResource);
  }

  @Patch(':id/stage')
  async updateStage(
    @Param('id') id: string,
    @Body('stage') stage: number,
    @Request() req: any,
  ) {
    return this.patientsService.updateStage(id, req.user.orgId, stage);
  }
}

import { Injectable } from '@nestjs/common';
import { PrismaService } from '../database/prisma.service';

@Injectable()
export class PatientsService {
  constructor(private prisma: PrismaService) {}

  async findAll(orgId: string) {
    return this.prisma.patient.findMany({
      where: { organizationId: orgId },
      orderBy: { createdAt: 'desc' },
    });
  }

  async findOne(id: string, orgId: string) {
    return this.prisma.patient.findFirst({
      where: { id, organizationId: orgId },
      include: { documents: true },
    });
  }

  async create(orgId: string, fhirResource: any) {
    return this.prisma.patient.create({
      data: {
        organizationId: orgId,
        fhirResource,
        lifecycleStage: 1, // Start at stage 1: Referral/Intake
      },
    });
  }

  async updateStage(id: string, orgId: string, stage: number) {
    return this.prisma.patient.update({
      where: { id, organizationId: orgId },
      data: { lifecycleStage: stage },
    });
  }
}

